void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        using var transaction = db.Database.BeginTransaction();
        db.Database.Migrate();
        transaction.Commit();
    });
}

arguments.new_str:
void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        // EF Core 9 applies migrations in its own transaction;
        // wrapping Migrate() in a user transaction now throws.
        db.Database.Migrate();
    });
}

